#include <omp.h>
#include <stdbool.h>

#define fp float
#define DEFAULT_ORDER 508

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode; 

void findK(	long height,
		knode *knodesD,
		long knodes_elem,
		record *recordsD,

		long *currKnodeD,
		long *offsetD,
		int *keysD, 
		record *ansD,
		int count,
		int order)
{
	int bid, thid;

#pragma omp parallel for private(bid, thid)
	for (bid = 0; bid < count; bid++) {
		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];
		int key = keysD[bid];
		for (int i = 0; i < height; i++) {
			// Each "thread" is thid from 0 to order-1
			// Simulate parallel threads by loop
			for (thid = 0; thid < order; thid++) {
				if ((knodesD[currKnode].keys[thid] <= key) && (knodesD[currKnode].keys[thid+1] > key)) {
					if (knodesD[offset].indices[thid] < knodes_elem) {
						offset = knodesD[offset].indices[thid];
					}
				}
			}
			currKnode = offset;
		}
		// Now assign answer for the matching keys
		for (thid = 0; thid < order; thid++) {
			if (knodesD[currKnode].keys[thid] == key) {
				ansD[bid].value = recordsD[knodesD[currKnode].indices[thid]].value;
			}
		}
		currKnodeD[bid] = currKnode;
		offsetD[bid] = offset;
	}
}

